// Generated by forge proof from forge-tui-sessions.md, tui-view-switcher.md, tui-specs-list.md, tui-spec-detail.md, tool-block-focus.md, tool-block-expand-toggle.md, tool-block-expanded-content.md
import { describe, test, expect, afterEach } from 'bun:test';
import { promises as fs } from 'fs';
import path from 'path';
import os from 'os';
import type { ForgeResult, SessionEvent, SpecManifest, SpecEntry, SpecRun } from './types.js';
import { loadManifest } from './specs.js';

// ── Helpers ──────────────────────────────────────────────────

let tmpDirs: string[] = [];

async function makeTmpDir(): Promise<string> {
  const raw = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-tui-test-'));
  const dir = await fs.realpath(raw);
  tmpDirs.push(dir);
  return dir;
}

afterEach(async () => {
  for (const d of tmpDirs) {
    await fs.rm(d, { recursive: true, force: true }).catch(() => {});
  }
  tmpDirs = [];
});

function makeSummary(overrides: Partial<ForgeResult> = {}): ForgeResult {
  return {
    startedAt: '2026-01-01T00:00:00Z',
    completedAt: '2026-01-01T00:01:00Z',
    durationSeconds: 60,
    status: 'success',
    prompt: 'test prompt',
    model: 'sonnet',
    cwd: '/test',
    ...overrides,
  };
}

function makeEntry(overrides: Partial<SpecEntry> = {}): SpecEntry {
  return {
    spec: 'feature.md',
    status: 'passed',
    runs: [],
    source: 'file',
    createdAt: '2026-01-01T00:00:00Z',
    updatedAt: '2026-01-01T00:00:00Z',
    ...overrides,
  };
}

function makeRun(overrides: Partial<SpecRun> = {}): SpecRun {
  return {
    runId: 'run-1',
    timestamp: '2026-01-01T00:00:00Z',
    resultPath: '.forge/results/2026-01-01T00-00-00Z',
    status: 'passed',
    costUsd: 0.5,
    durationSeconds: 60,
    ...overrides,
  };
}

async function setupForge(dir: string, manifest?: SpecManifest): Promise<void> {
  const forgeDir = path.join(dir, '.forge');
  await fs.mkdir(forgeDir, { recursive: true });
  if (manifest) {
    await fs.writeFile(path.join(forgeDir, 'specs.json'), JSON.stringify(manifest));
  }
}

async function setupResults(dir: string, results: Array<{ ts: string; summary: ForgeResult }>): Promise<void> {
  const resultsDir = path.join(dir, '.forge', 'results');
  for (const { ts, summary } of results) {
    const runDir = path.join(resultsDir, ts);
    await fs.mkdir(runDir, { recursive: true });
    await fs.writeFile(path.join(runDir, 'summary.json'), JSON.stringify(summary));
  }
}

async function setupSession(dir: string, sessionId: string, events: SessionEvent[]): Promise<string> {
  const sessionDir = path.join(dir, '.forge', 'sessions', sessionId);
  await fs.mkdir(sessionDir, { recursive: true });
  const eventsPath = path.join(sessionDir, 'events.jsonl');
  const streamPath = path.join(sessionDir, 'stream.log');
  await fs.writeFile(eventsPath, events.map(e => JSON.stringify(e)).join('\n'));
  await fs.writeFile(streamPath, '[Session started]\n');
  return eventsPath;
}

/**
 * Replicate the groupEvents logic from tui.tsx for testing.
 * Groups flat events into tool blocks, text blocks, and session dividers.
 */
interface ToolBlock { kind: 'tool'; start: SessionEvent; result?: SessionEvent }
interface TextBlock { kind: 'text'; content: string; timestamp: string }
interface SessionStartBlock { kind: 'session_start'; event: SessionEvent }
interface SessionEndBlock { kind: 'session_end'; event: SessionEvent }
type GroupedBlock = ToolBlock | TextBlock | SessionStartBlock | SessionEndBlock;

function groupEvents(events: SessionEvent[]): GroupedBlock[] {
  const blocks: GroupedBlock[] = [];
  let textParts: string[] = [];
  let textTimestamp = '';
  const pendingById = new Map<string, number>();
  const pendingQueue: number[] = [];

  const flushText = () => {
    if (textParts.length > 0) {
      blocks.push({ kind: 'text', content: textParts.join(''), timestamp: textTimestamp });
      textParts = [];
      textTimestamp = '';
    }
  };

  for (const event of events) {
    switch (event.type) {
      case 'session_start':
        flushText();
        blocks.push({ kind: 'session_start', event });
        break;
      case 'session_end':
        flushText();
        blocks.push({ kind: 'session_end', event });
        break;
      case 'text_delta':
        if (textParts.length === 0) textTimestamp = event.timestamp;
        textParts.push(event.content);
        break;
      case 'thinking_delta':
        // Hidden by default
        break;
      case 'tool_call_start': {
        flushText();
        const idx = blocks.length;
        blocks.push({ kind: 'tool', start: event });
        if (event.toolUseId) {
          pendingById.set(event.toolUseId, idx);
        } else {
          pendingQueue.push(idx);
        }
        break;
      }
      case 'tool_call_result': {
        if (event.toolUseId && pendingById.has(event.toolUseId)) {
          const idx = pendingById.get(event.toolUseId)!;
          (blocks[idx] as ToolBlock).result = event;
          pendingById.delete(event.toolUseId);
        } else if (pendingQueue.length > 0) {
          const idx = pendingQueue.shift()!;
          (blocks[idx] as ToolBlock).result = event;
        }
        break;
      }
    }
  }
  flushText();
  return blocks;
}

