// ── Session list: data loading from .forge/results/ ──────────

describe('session list data loading', () => {
  test('sessions populated from summary.json files sorted by recency', async () => {
    const dir = await makeTmpDir();
    await setupForge(dir);
    await setupResults(dir, [
      { ts: '2026-01-01T00-00-00Z', summary: makeSummary({ sessionId: 's1', startedAt: '2026-01-01T00:00:00Z' }) },
      { ts: '2026-01-02T00-00-00Z', summary: makeSummary({ sessionId: 's2', startedAt: '2026-01-02T00:00:00Z' }) },
      { ts: '2026-01-03T00-00-00Z', summary: makeSummary({ sessionId: 's3', startedAt: '2026-01-03T00:00:00Z' }) },
    ]);

    const resultsDir = path.join(dir, '.forge', 'results');
    const entries = await fs.readdir(resultsDir);
    expect(entries).toHaveLength(3);

    // Summaries can be loaded and sorted by startedAt
    const summaries: ForgeResult[] = [];
    for (const entry of entries) {
      const raw = await fs.readFile(path.join(resultsDir, entry, 'summary.json'), 'utf-8');
      summaries.push(JSON.parse(raw));
    }
    summaries.sort((a, b) => b.startedAt.localeCompare(a.startedAt));
    expect(summaries[0].sessionId).toBe('s3'); // newest first
    expect(summaries[2].sessionId).toBe('s1'); // oldest last
  });

  test('session row data includes all required display fields', () => {
    const summary = makeSummary({
      sessionId: 's1',
      specPath: '/repo/specs/auth.md',
      costUsd: 1.50,
      durationSeconds: 120,
      model: 'opus',
      status: 'success',
    });

    // Status: 'success' -> icon '+', Failed -> 'x', Running -> '>'
    const statusIcon = summary.status === 'success' ? '+' : 'x';
    expect(statusIcon).toBe('+');
    expect(summary.model).toBe('opus');
    expect(summary.costUsd).toBe(1.50);
    expect(summary.durationSeconds).toBe(120);
    // spec name extracted from path
    const specName = summary.specPath ? path.basename(summary.specPath) : '--';
    expect(specName).toBe('auth.md');
  });

  test('latest-session.json identifies running sessions', async () => {
    const dir = await makeTmpDir();
    await setupForge(dir);

    const sessionInfo = {
      sessionId: 'running-session',
      startedAt: new Date().toISOString(),
      model: 'sonnet',
      cwd: dir,
      logPath: path.join(dir, '.forge', 'sessions', 'running-session', 'stream.log'),
    };
    await fs.writeFile(
      path.join(dir, '.forge', 'latest-session.json'),
      JSON.stringify(sessionInfo),
    );

    const raw = await fs.readFile(path.join(dir, '.forge', 'latest-session.json'), 'utf-8');
    const parsed = JSON.parse(raw);
    expect(parsed.sessionId).toBe('running-session');
    // events.jsonl derived from logPath
    const eventsPath = parsed.logPath.replace('stream.log', 'events.jsonl');
    expect(eventsPath).toContain('events.jsonl');
  });

  test('empty results directory yields no sessions', async () => {
    const dir = await makeTmpDir();
    await setupForge(dir);
    await fs.mkdir(path.join(dir, '.forge', 'results'), { recursive: true });

    const entries = await fs.readdir(path.join(dir, '.forge', 'results'));
    expect(entries).toHaveLength(0);
  });
});

// ── Session detail: events.jsonl parsing and grouping ────────

describe('session detail event grouping', () => {
  test('text_delta events merge into single text block', () => {
    const events: SessionEvent[] = [
      { type: 'session_start', timestamp: 'ts', sessionId: 's', model: 'm', prompt: 'p' },
      { type: 'text_delta', timestamp: 'ts1', content: 'Hello ' },
      { type: 'text_delta', timestamp: 'ts2', content: 'world.' },
    ];
    const blocks = groupEvents(events);
    const textBlocks = blocks.filter(b => b.kind === 'text');
    expect(textBlocks).toHaveLength(1);
    expect((textBlocks[0] as TextBlock).content).toBe('Hello world.');
  });

  test('tool_call_start and tool_call_result pair by toolUseId', () => {
    const events: SessionEvent[] = [
      { type: 'tool_call_start', timestamp: 'ts1', toolName: 'Read', toolUseId: 'id-1', input: { file_path: 'a.ts' } },
      { type: 'tool_call_start', timestamp: 'ts2', toolName: 'Bash', toolUseId: 'id-2', input: { command: 'ls' } },
      { type: 'tool_call_result', timestamp: 'ts3', toolName: 'Bash', toolUseId: 'id-2', output: 'dir listing' },
      { type: 'tool_call_result', timestamp: 'ts4', toolName: 'Read', toolUseId: 'id-1', output: 'file content' },
    ];
    const blocks = groupEvents(events);
    const toolBlocks = blocks.filter(b => b.kind === 'tool') as ToolBlock[];
    expect(toolBlocks).toHaveLength(2);
    // First tool block (Read) paired with its result
    expect((toolBlocks[0].start as any).toolName).toBe('Read');
    expect((toolBlocks[0].result as any).output).toBe('file content');
    // Second tool block (Bash) paired with its result
    expect((toolBlocks[1].start as any).toolName).toBe('Bash');
    expect((toolBlocks[1].result as any).output).toBe('dir listing');
  });

  test('tool_call_start without toolUseId uses FIFO matching', () => {
    const events: SessionEvent[] = [
      { type: 'tool_call_start', timestamp: 'ts1', toolName: 'Read', input: { file_path: 'a.ts' } },
      { type: 'tool_call_result', timestamp: 'ts2', toolName: 'Read', output: 'content' },
    ];
    const blocks = groupEvents(events);
    const toolBlocks = blocks.filter(b => b.kind === 'tool') as ToolBlock[];
    expect(toolBlocks).toHaveLength(1);
    expect(toolBlocks[0].result).toBeDefined();
    expect((toolBlocks[0].result as any).output).toBe('content');
  });

  test('thinking_delta events are skipped (hidden by default)', () => {
    const events: SessionEvent[] = [
      { type: 'session_start', timestamp: 'ts', sessionId: 's', model: 'm', prompt: 'p' },
      { type: 'thinking_delta', timestamp: 'ts1', content: 'internal reasoning' },
      { type: 'text_delta', timestamp: 'ts2', content: 'visible text' },
    ];
    const blocks = groupEvents(events);
    const allKinds = blocks.map(b => b.kind);
    expect(allKinds).not.toContain('thinking');
    expect(allKinds).toContain('session_start');
    expect(allKinds).toContain('text');
  });

  test('text block flushed before tool block', () => {
    const events: SessionEvent[] = [
      { type: 'text_delta', timestamp: 'ts1', content: 'reasoning' },
      { type: 'tool_call_start', timestamp: 'ts2', toolName: 'Bash', input: { command: 'ls' } },
    ];
    const blocks = groupEvents(events);
    expect(blocks[0].kind).toBe('text');
    expect(blocks[1].kind).toBe('tool');
  });

  test('session_start and session_end create divider blocks', () => {
    const events: SessionEvent[] = [
      { type: 'session_start', timestamp: 'ts1', sessionId: 's1', model: 'sonnet', prompt: 'task' },
      { type: 'text_delta', timestamp: 'ts2', content: 'done' },
      { type: 'session_end', timestamp: 'ts3', durationSeconds: 10, status: 'success' },
    ];
    const blocks = groupEvents(events);
    expect(blocks[0].kind).toBe('session_start');
    expect(blocks[1].kind).toBe('text');
    expect(blocks[2].kind).toBe('session_end');
  });

  test('empty events array returns empty blocks', () => {
    const blocks = groupEvents([]);
    expect(blocks).toHaveLength(0);
  });

  test('tool block indices can be collected for focus navigation', () => {
    const events: SessionEvent[] = [
      { type: 'session_start', timestamp: 'ts', sessionId: 's', model: 'm', prompt: 'p' },
      { type: 'text_delta', timestamp: 'ts1', content: 'analysis' },
      { type: 'tool_call_start', timestamp: 'ts2', toolName: 'Read', input: {} },
      { type: 'tool_call_result', timestamp: 'ts3', toolName: 'Read', output: '' },
      { type: 'text_delta', timestamp: 'ts4', content: 'more text' },
      { type: 'tool_call_start', timestamp: 'ts5', toolName: 'Edit', input: {} },
      { type: 'tool_call_result', timestamp: 'ts6', toolName: 'Edit', output: '' },
      { type: 'tool_call_start', timestamp: 'ts7', toolName: 'Bash', input: {} },
      { type: 'tool_call_result', timestamp: 'ts8', toolName: 'Bash', output: '' },
    ];
    const blocks = groupEvents(events);
    const toolBlockIndices = blocks
      .map((b, i) => b.kind === 'tool' ? i : -1)
      .filter(i => i >= 0);
    expect(toolBlockIndices).toHaveLength(3);
    // n/N navigation: focusedToolIndex cycles through these indices
  });
});

// ── events.jsonl parsing from file ───────────────────────────

describe('events.jsonl file parsing', () => {
  test('events parsed from JSONL format with all event types', async () => {
    const dir = await makeTmpDir();
    await setupForge(dir);

    const events: SessionEvent[] = [
      { type: 'session_start', timestamp: '2026-01-01T00:00:00Z', sessionId: 's1', model: 'sonnet', prompt: 'test' },
      { type: 'thinking_delta', timestamp: '2026-01-01T00:00:01Z', content: 'Analyzing...' },
      { type: 'text_delta', timestamp: '2026-01-01T00:00:02Z', content: 'Found it.' },
      { type: 'tool_call_start', timestamp: '2026-01-01T00:00:03Z', toolName: 'Read', input: { file_path: 'src/index.ts' } },
      { type: 'tool_call_result', timestamp: '2026-01-01T00:00:04Z', toolName: 'Read', output: 'file contents' },
      { type: 'session_end', timestamp: '2026-01-01T00:00:10Z', durationSeconds: 10, status: 'success' },
    ];

    const eventsPath = await setupSession(dir, 's1', events);
    const content = await fs.readFile(eventsPath, 'utf-8');
    const parsed = content.split('\n').filter(l => l.trim()).map(l => JSON.parse(l) as SessionEvent);

    expect(parsed).toHaveLength(6);
    expect(parsed[0].type).toBe('session_start');
    expect(parsed[1].type).toBe('thinking_delta');
    expect(parsed[2].type).toBe('text_delta');
    expect(parsed[3].type).toBe('tool_call_start');
    expect(parsed[4].type).toBe('tool_call_result');
    expect(parsed[5].type).toBe('session_end');
  });

  test('malformed JSONL lines are skipped gracefully', async () => {
    const dir = await makeTmpDir();
    await setupForge(dir);

    const sessionDir = path.join(dir, '.forge', 'sessions', 's1');
    await fs.mkdir(sessionDir, { recursive: true });
    const eventsPath = path.join(sessionDir, 'events.jsonl');

    const lines = [
      JSON.stringify({ type: 'session_start', timestamp: 'ts', sessionId: 's1', model: 'sonnet', prompt: 'test' }),
      'not valid json {{{',
      JSON.stringify({ type: 'text_delta', timestamp: 'ts', content: 'hello' }),
    ];
    await fs.writeFile(eventsPath, lines.join('\n'));

    const content = await fs.readFile(eventsPath, 'utf-8');
    const parsed: SessionEvent[] = [];
    for (const line of content.split('\n')) {
      if (!line.trim()) continue;
      try { parsed.push(JSON.parse(line)); } catch { /* skip */ }
    }
    expect(parsed).toHaveLength(2);
  });

  test('events.jsonl path derived from stream.log via dirname', () => {
    // deriveEventsPath with logPath
    const logPath = '/repo/.forge/sessions/abc123/stream.log';
    const eventsPath = path.join(path.dirname(logPath), 'events.jsonl');
    expect(eventsPath).toBe('/repo/.forge/sessions/abc123/events.jsonl');
  });

  test('events.jsonl path derived from sessionId and cwd', () => {
    const sessionId = 'def456';
    const cwd = '/repo';
    const eventsPath = path.join(cwd, '.forge', 'sessions', sessionId, 'events.jsonl');
    expect(eventsPath).toBe('/repo/.forge/sessions/def456/events.jsonl');
  });
});

// ── Tab bar: view switcher ───────────────────────────────────

describe('tab bar view switcher', () => {
  test('Tab type supports sessions, specs, pipeline', () => {
    const tabs: Array<'sessions' | 'specs' | 'pipeline'> = ['sessions', 'specs', 'pipeline'];
    expect(tabs).toHaveLength(3);
    expect(tabs).toContain('sessions');
    expect(tabs).toContain('specs');
    expect(tabs).toContain('pipeline');
  });

  test('tab cycling wraps around: sessions -> specs -> pipeline -> sessions', () => {
    const tabs = ['sessions', 'specs', 'pipeline'] as const;
    let current = 0;
    // Press tab 3 times
    current = (current + 1) % tabs.length; expect(tabs[current]).toBe('specs');
    current = (current + 1) % tabs.length; expect(tabs[current]).toBe('pipeline');
    current = (current + 1) % tabs.length; expect(tabs[current]).toBe('sessions');
  });
});

// ── Specs list: manifest loading and display data ────────────

describe('specs list data', () => {
  test('loadManifest returns entries for specs list', async () => {
    const dir = await makeTmpDir();
    await setupForge(dir, {
      version: 1,
      specs: [
        makeEntry({ spec: 'auth/login.md', status: 'passed', runs: [makeRun()] }),
        makeEntry({ spec: 'auth/oauth.md', status: 'failed', runs: [makeRun({ status: 'failed' })] }),
        makeEntry({ spec: 'db/migrate.md', status: 'pending' }),
      ],
    });

    const manifest = await loadManifest(dir);
    expect(manifest.specs).toHaveLength(3);

    // Can group by directory
    const authSpecs = manifest.specs.filter(s => s.spec.startsWith('auth/'));
    expect(authSpecs).toHaveLength(2);
    const dbSpecs = manifest.specs.filter(s => s.spec.startsWith('db/'));
    expect(dbSpecs).toHaveLength(1);
  });

  test('total cost per spec computed from runs', () => {
    const entry = makeEntry({
      runs: [
        makeRun({ costUsd: 1.50, durationSeconds: 60 }),
        makeRun({ costUsd: 2.00, durationSeconds: 90, runId: 'run-2', timestamp: '2026-01-02T00:00:00Z' }),
      ],
    });
    const totalCost = entry.runs.reduce((s, r) => s + (r.costUsd ?? 0), 0);
    const totalDuration = entry.runs.reduce((s, r) => s + r.durationSeconds, 0);
    expect(totalCost).toBeCloseTo(3.50, 2);
    expect(totalDuration).toBe(150);
  });

  test('empty manifest shows no specs', async () => {
    const dir = await makeTmpDir();
    await setupForge(dir, { version: 1, specs: [] });
    const manifest = await loadManifest(dir);
    expect(manifest.specs).toHaveLength(0);
  });

  test('missing manifest file returns empty manifest gracefully', async () => {
    const dir = await makeTmpDir();
    // No .forge directory at all
    const manifest = await loadManifest(dir);
    expect(manifest.specs).toHaveLength(0);
    expect(manifest.version).toBe(1);
  });

  test('status icon mapping: + for passed, x for failed, - for pending', () => {
    const iconMap: Record<string, string> = {
      passed: '+', failed: 'x', pending: '-', running: '>',
    };
    expect(iconMap.passed).toBe('+');
    expect(iconMap.failed).toBe('x');
    expect(iconMap.pending).toBe('-');
    expect(iconMap.running).toBe('>');
  });

  test('directory grouping extracts parent dir from spec path', () => {
    const specs = ['auth/login.md', 'auth/oauth.md', 'db/migrate.md', 'standalone.md'];
    const groups = new Map<string, string[]>();
    for (const spec of specs) {
      const dir = spec.includes('/') ? path.dirname(spec) : '.';
      if (!groups.has(dir)) groups.set(dir, []);
      groups.get(dir)!.push(spec);
    }
    expect(groups.get('auth')).toHaveLength(2);
    expect(groups.get('db')).toHaveLength(1);
    expect(groups.get('.')).toHaveLength(1);
  });
});

// ── Spec detail: run history ─────────────────────────────────

describe('spec detail run history', () => {
  test('run entries have all display fields', () => {
    const entry = makeEntry({
      spec: 'auth/login.md',
      runs: [
        makeRun({
          runId: 'run-1',
          timestamp: '2026-01-01T00:00:00Z',
          status: 'failed',
          costUsd: 1.00,
          durationSeconds: 30,
          numTurns: 10,
          verifyAttempts: 2,
        }),
        makeRun({
          runId: 'run-2',
          timestamp: '2026-01-02T00:00:00Z',
          status: 'passed',
          costUsd: 2.00,
          durationSeconds: 60,
          numTurns: 25,
          verifyAttempts: 0,
        }),
      ],
    });

    expect(entry.runs).toHaveLength(2);
    // Newest first (sorted by caller)
    const sorted = [...entry.runs].sort((a, b) => b.timestamp.localeCompare(a.timestamp));
    expect(sorted[0].runId).toBe('run-2');
    expect(sorted[0].numTurns).toBe(25);
    expect(sorted[1].runId).toBe('run-1');
    expect(sorted[1].verifyAttempts).toBe(2);
  });

  test('empty runs array shows no run history', () => {
    const entry = makeEntry({ runs: [] });
    expect(entry.runs).toHaveLength(0);
  });

  test('session events path can be derived from resultPath', () => {
    // resultPath stores the result directory, sessionId can be derived from summary
    const run = makeRun({ resultPath: '.forge/results/2026-01-01T00-00-00Z' });
    expect(run.resultPath).toContain('.forge/results/');
    // The TUI reads summary.json from resultPath, then uses sessionId for events
  });

  test('spec metadata includes status, source, timestamps', () => {
    const entry = makeEntry({
      spec: 'auth/login.md',
      status: 'passed',
      source: 'file',
      createdAt: '2026-01-01T00:00:00Z',
      updatedAt: '2026-01-02T00:00:00Z',
    });
    expect(entry.status).toBe('passed');
    expect(entry.source).toBe('file');
    expect(entry.createdAt).toBe('2026-01-01T00:00:00Z');
    expect(entry.updatedAt).toBe('2026-01-02T00:00:00Z');
  });
});

